package com.chaobo.scm.supplier.interfaces.web;

import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.contract.*;import jakarta.servlet.http.HttpServletRequest;import jakarta.validation.constraints.*;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.security.oauth2.jwt.Jwt;import org.springframework.web.bind.annotation.*;import java.time.LocalDate;
@RestController @RequestMapping("/api/supplier/v1/price-agreements") public class PriceAgreementController {private final PriceAgreementQueryApplicationService service;public PriceAgreementController(PriceAgreementQueryApplicationService service){this.service=service;}@GetMapping public ApiResponse<PageResult<PriceAgreementView>> page(@RequestParam(required=false)Long supplierId,@RequestParam(required=false)String skuCode,@RequestParam(defaultValue="1")int pageNo,@RequestParam(defaultValue="20")int pageSize,@AuthenticationPrincipal Jwt jwt,HttpServletRequest request){return ApiResponse.success(service.page(supplierId,scope(jwt),skuCode,pageNo,pageSize),request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}@GetMapping("/{id}")public ApiResponse<PriceAgreementView> detail(@PathVariable long id,@AuthenticationPrincipal Jwt jwt,HttpServletRequest request){return ApiResponse.success(service.detail(id,scope(jwt)),request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}@GetMapping("/effective-price")public ApiResponse<PriceAgreementView.Line> effectivePrice(@RequestParam @Positive long supplierId,@RequestParam @NotBlank String skuCode,@RequestParam @NotBlank String currency,@RequestParam(required=false)LocalDate businessDate,HttpServletRequest request){return ApiResponse.success(service.validate(supplierId,skuCode,currency,businessDate),request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}private Long scope(Jwt jwt){Number n=jwt.hasClaim("supplier_id")?jwt.getClaim("supplier_id"):null;return n==null?null:n.longValue();}}
